const results = $input.first().json.results || [];
const staticData = $getWorkflowStaticData('global');

// Reset daily
const today = new Date().toISOString().split('T')[0];
if (staticData.lastResetDate !== today) {
  staticData.alertedCampaigns = [];
  staticData.lastResetDate = today;
}
if (!Array.isArray(staticData.alertedCampaigns)) staticData.alertedCampaigns = [];

const campaignsToAlert = [];

for (const r of results) {
  const campaignName = r.campaign.name;
  const cost = (r.metrics.costMicros || 0) / 1_000_000;
  const conversions = r.metrics.conversions || 0;

  if (conversions === 0) continue;

  const cpa = cost / conversions;

  if (cpa > 100 && !staticData.alertedCampaigns.includes(campaignName)) {
    campaignsToAlert.push({
      campagne: campaignName,
      cpa: cpa.toFixed(2),
      conversions: conversions,
      depense: cost.toFixed(2)
    });
    staticData.alertedCampaigns.push(campaignName);
  }
}

if (campaignsToAlert.length === 0) return [];

return campaignsToAlert.map(c => ({ json: c }));
